"""ATTACK 1: Firewall A bypass attempts.
The runner passes the builder only (corpus, claim_guard). Can the builder reach the claims?
"""
import gc
from assay_engine.baseline.toolkit import BaselineArtifact
from assay_engine.contracts.claims import ClaimRecord
from assay_engine.contracts.schema import Corpus, Unit
from assay_engine.methodology.adjudication import adjudicate
from assay_engine.methodology.firewalls import FirewallViolation
from assay_engine.methodology.hypothesis import Hypothesis, HypothesisKind, HypothesisOrigin
from assay_engine.methodology.verdict import Verdict


class Claims:
    SECRET = "TOP-SECRET-CLAIM-ASSERTION"
    def __init__(self, claims): self._claims = claims
    def claims(self): return list(self._claims)
    def claim_fingerprint(self): return "fp"


def claim(cid): return ClaimRecord(claim_id=cid, subject=cid, referents=(cid,),
                                    assertion={"expected": Claims.SECRET})

def hyp_for(c): return Hypothesis(hypothesis_id=f"H-{c.claim_id}", statement="s",
    kind=HypothesisKind.WHOLE_CORPUS, origin=HypothesisOrigin.EXTERNAL_CLAIM,
    test_name="t", decision_rule="r", source_claim_id=c.claim_id,
    locked_at="2026-06-16T00:00:00Z", timestamp_proof="rfc3161:demo")

def confirmer(h, b, c): return Verdict.supported(c.claim_id, "r")

corpus = Corpus(units=(Unit("a","x"), Unit("b","y")))
the_claims = Claims([claim("c1"), claim("c2")])

results = {}

# --- Attack 1a: read guard attributes/internals
class AttrBuilder:
    def build(self, corpus, *, claim_guard):
        found = []
        for name in dir(claim_guard):
            try:
                v = getattr(claim_guard, name)
            except Exception:
                continue
            s = repr(v)
            if Claims.SECRET in s or "c1" in s or isinstance(v, Claims):
                found.append((name, s[:80]))
        # also probe __dict__
        d = getattr(claim_guard, "__dict__", {})
        results["1a_guard_attrs_leak"] = found
        results["1a_guard_dict"] = {k: repr(v)[:60] for k,v in d.items()}
        return BaselineArtifact(corpus_fingerprint="fp", contents={})

adjudicate(corpus, the_claims, baseline_builder=AttrBuilder(), hypothesis_for=hyp_for, confirm=confirmer)

# --- Attack 1b: gc.get_referrers on the guard, walk to find Claims
class GCReferrerBuilder:
    def build(self, corpus, *, claim_guard):
        leaked = []
        # walk referrers of the guard -> the runner frame -> locals -> claims_source
        seen = set()
        frontier = [claim_guard]
        depth = 0
        while frontier and depth < 4:
            nxt = []
            for obj in frontier:
                for ref in gc.get_referrers(obj):
                    if id(ref) in seen: continue
                    seen.add(id(ref))
                    if isinstance(ref, Claims):
                        leaked.append(("direct", ref.claims()))
                    nxt.append(ref)
            frontier = nxt
            depth += 1
        results["1b_gc_referrers_leak"] = [str(l)[:120] for l in leaked]
        return BaselineArtifact(corpus_fingerprint="fp", contents={})

adjudicate(corpus, the_claims, baseline_builder=GCReferrerBuilder(), hypothesis_for=hyp_for, confirm=confirmer)

# --- Attack 1c: walk the calling frame stack
import sys
class FrameBuilder:
    def build(self, corpus, *, claim_guard):
        leaked = []
        f = sys._getframe()
        while f is not None:
            for k, v in f.f_locals.items():
                if isinstance(v, Claims):
                    leaked.append((f.f_code.co_name, k, v.claims()))
            f = f.f_back
        results["1c_frame_walk_leak"] = [str(l)[:120] for l in leaked]
        return BaselineArtifact(corpus_fingerprint="fp", contents={})

adjudicate(corpus, the_claims, baseline_builder=FrameBuilder(), hypothesis_for=hyp_for, confirm=confirmer)

# --- Attack 1d: gc.get_objects for any Claims instance (whole-heap)
class HeapBuilder:
    def build(self, corpus, *, claim_guard):
        found = [o for o in gc.get_objects() if isinstance(o, Claims)]
        results["1d_heap_scan_leak"] = [str(o.claims())[:120] for o in found]
        return BaselineArtifact(corpus_fingerprint="fp", contents={})

adjudicate(corpus, the_claims, baseline_builder=HeapBuilder(), hypothesis_for=hyp_for, confirm=confirmer)

# --- Attack 1e: corpus path
class CorpusBuilder:
    def build(self, corpus, *, claim_guard):
        s = repr(corpus)
        results["1e_corpus_contains_secret"] = Claims.SECRET in s
        return BaselineArtifact(corpus_fingerprint="fp", contents={})

adjudicate(corpus, the_claims, baseline_builder=CorpusBuilder(), hypothesis_for=hyp_for, confirm=confirmer)

import json
print(json.dumps(results, indent=2, default=str))
PYEOF
